export function setup() {
  // Get initial token for refresh tests
  const loginRes = http.post(`${BASE_URL}/api/users/token/login`, JSON.stringify({
    username: 'default',
    password: '1234',
  }), { headers: { 'Content-Type': 'application/json' } });

  check(loginRes, {
    'setup: login succeeded': (r) => r.status === 200,
  });

  const token = loginRes.json('token');
  return { token: token };
}

export function smokeTest(data) {
  group('Smoke: Login', function () {
    const res = http.post(`${BASE_URL}/api/users/token/login`, JSON.stringify({
      username: 'default',
      password: '1234',
    }), {
      headers: { 'Content-Type': 'application/json' },
      tags: { endpoint: '/api/users/token/login', type: 'auth', scenario: 'smoke' },
    });
    check(res, {
      'login returns 200': (r) => r.status === 200,
      'has token': (r) => {
        try { return JSON.parse(r.body).token !== undefined; } catch { return false; }
      },
      'response time < 1s': (r) => r.timings.duration < 1000,
    });
  });

  group('Smoke: Token Refresh', function () {
    const res = http.post(`${BASE_URL}/api/users/token/refresh`, JSON.stringify({
      token: data.token,
    }), {
      headers: { 'Content-Type': 'application/json' },
      tags: { endpoint: '/api/users/token/refresh', type: 'auth', scenario: 'smoke' },
    });
    // Token refresh may not exist yet on the live server — check gracefully
    check(res, {
      'refresh returns 200 or 404': (r) => r.status === 200 || r.status === 404,
    });
  });
}

export default function (data) {
  group('Login Flow', function () {
    const loginRes = http.post(`${BASE_URL}/api/users/token/login`, JSON.stringify({
      username: 'default',
      password: '1234',
    }), {
      headers: { 'Content-Type': 'application/json' },
      tags: { endpoint: '/api/users/token/login', type: 'auth', scenario: 'load_test' },
    });

    const loginOk = check(loginRes, {
      'login returns 200': (r) => r.status === 200,
      'response time < 1s': (r) => r.timings.duration < 1000,
      'has token': (r) => {
        try { return JSON.parse(r.body).token !== undefined; } catch { return false; }
      },
    });

    errorRate.add(!loginOk);
    loginDuration.add(loginRes.timings.duration);

    // If login succeeded, test token refresh
    if (loginOk && loginRes.status === 200) {
      const token = loginRes.json('token');
      sleep(0.5); // Simulate real-world delay between login and refresh

      const refreshRes = http.post(`${BASE_URL}/api/users/token/refresh`, JSON.stringify({
        token: token,
      }), {
        headers: { 'Content-Type': 'application/json' },
        tags: { endpoint: '/api/users/token/refresh', type: 'auth', scenario: 'load_test' },
      });

      const refreshOk = check(refreshRes, {
        'refresh returns 200 or 404': (r) => r.status === 200 || r.status === 404,
        'refresh time < 1s': (r) => r.timings.duration < 1000,
      });

      errorRate.add(!refreshOk);
      refreshDuration.add(refreshRes.timings.duration);
    }
  });

  // Rate limit test: intentionally fail auth to verify rate limiting works
  group('Rate Limit Verification', function () {
    const res = http.post(`${BASE_URL}/api/users/token/login`, JSON.stringify({
      username: 'nonexistent',
      password: 'wrong',
    }), {
      headers: { 'Content-Type': 'application/json' },
      tags: { endpoint: '/api/users/token/login', type: 'auth_fail', scenario: 'rate_limit' },
    });
    check(res, {
      'bad creds returns 401 or 429': (r) => r.status === 401 || r.status === 429,
    });
  });

  sleep(1); // Spacing between iterations to avoid triggering rate limit
}

export function baselineTest(data) {
  group('Baseline Regression', function () {
    const ratingsRes = http.get(`${BASE_URL}/api/ratings`, {
      headers: { 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/ratings', scenario: 'baseline' },
    });
    check(ratingsRes, {
      'ratings 200': (r) => r.status === 200,
    });

    const pizzaRes = http.post(`${BASE_URL}/api/pizza`, JSON.stringify({}), {
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/pizza', scenario: 'baseline' },
    });
    check(pizzaRes, {
      'pizza 200': (r) => r.status === 200,
    });
  });
  sleep(0.5);
}

